mapper.select:
SELECT * FROM projects


        AND event_date >= CONCAT(#{fiscalYear}, '-04-01')
        AND event_date <  CONCAT(#{fiscalYear} + 1, '-04-01')


        AND budget_type_id = #{budgetTypeId}


        AND MONTH(event_date) = #{month}


        AND target_category = #{targetCategory}


        AND name LIKE CONCAT('%', #{projectName}, '%')


        AND is_printed = FALSE


        AND is_printed = TRUE


ORDER BY event_date DESC, id DESC
